import { TickRendererProps } from '@visx/axis';
import { getTicks } from '@visx/scale';
import type { ScaleBand } from 'd3-scale';

import { DivAxisWrapper } from './DivAxisWrapper.js';
import type { TruncationMode } from '../../../../../typography/text-ellipsis/TextEllipsis.js';
import { AxisBottom } from '../AxisBottom.js';
import { axisFontProps, EMOJI_REGEX } from '../constants.js';
import { TickLabelLayout, TickCategory } from '../types.js';
import { TickLabel } from './TickLabel.js';
import { getXTickMaxSize } from '../utils/calculate-axis-size.js';
import { getTickLabelPropsForCategoryAxis } from '../utils/get-tick-label-props.js';
import { isTickLabelSpaceAvailable } from '../utils/is-tick-label-visible.js';
import { getCategoryBottomAxisProps } from './utils/getCategoryBottomAxisProps.js';

/**
 * @internal
 */
export interface CategoryBottomAxisProps {
  scale: ScaleBand<string>;
  containerWidth: number;
  containerHeight: number;
  categories: TickCategory;
  label?: string;
  tickLabelLayout?: TickLabelLayout;
  truncationMode?: TruncationMode;
  isVerticalLayout?: boolean;
}

/**
 * @internal
 */
export const CategoryBottomAxis = (props: CategoryBottomAxisProps) => {
  const {
    scale,
    containerWidth,
    categories,
    containerHeight,
    tickLabelLayout = 'horizontal',
    label,
    truncationMode = 'end',
  } = props;

  const ticks = getTicks(scale);
  const tickNames = ticks.map((tickId) => categories[tickId]) ?? 'Unknown';
  const isTickRotated = tickLabelLayout === 'vertical';
  const isTickLabelVisible = isTickLabelSpaceAvailable(scale.step());

  const maxSize = getXTickMaxSize(
    containerHeight,
    containerWidth,
    isTickRotated,
    scale,
    label,
  );

  const tickLabelProps = getTickLabelPropsForCategoryAxis(
    'bottom',
    tickLabelLayout,
  );

  const tickNameHasEmoji = tickNames.some((name) => EMOJI_REGEX.test(name));

  const tickFormat = (_: unknown, index: number) => tickNames[index];
  return isTickLabelVisible ? (
    <DivAxisWrapper
      divAxisStyle={axisFontProps}
      ticks={tickNames}
      label={label}
      isTickVertical
      isTickRotated={isTickRotated}
    >
      <AxisBottom
        role="graphics-symbol"
        aria-label="category axis bottom"
        scale={scale}
        containerSize={containerWidth}
        height={containerHeight}
        tickComponent={({
          x: renderX,
          y: renderY,
          ...rest
        }: Omit<
          TickRendererProps,
          | 'aria-dropeffect'
          | 'aria-grabbed'
          | 'onKeyPress'
          | 'onKeyPressCapture'
        >) => {
          const {
            x,
            y,
            foreignObjectInlineStyle,
            foreignObjectContentInlineStyle,
          } = getCategoryBottomAxisProps(
            renderX,
            isTickRotated,
            maxSize,
            tickNameHasEmoji,
          );

          return (
            <TickLabel
              foreignObjectInlineStyle={foreignObjectInlineStyle}
              foreignObjectContentInlineStyle={foreignObjectContentInlineStyle}
              isTickRotated={isTickRotated}
              truncationMode={truncationMode}
              maxSize={maxSize}
              x={x}
              y={y}
              {...rest}
            />
          );
        }}
        tickValues={ticks}
        tickLabelProps={tickLabelProps}
        tickFormat={tickFormat}
        label={label}
        width={containerWidth}
      />
    </DivAxisWrapper>
  ) : null;
};

CategoryBottomAxis['displayName'] = 'CategoryBottomAxis';
